INSERT INTO public.quizzes (era, region, question, options, correct_option_index, explanation) VALUES
('joseon', '완주', '완주 송광사에 있는 문화유산 중 하나인 보물 제1243호 대웅전과 관련된 특징으로 옳은 것은 무엇인가요?', array['벽면 전체가 도자기 타일로 마감되어 있다.', '임진왜란 때 소실된 후 조선 인조 대에 재건되었으며 삼세불상이 봉안되어 있다.', '지하에 석굴암과 같은 인공 석굴이 존재한다.', '국내에서 가장 오래된 철조 비로자나불좌상이 있다.'], 1, '완주 송광사 대웅전은 보물 제1243호로 지정되어 있으며, 광해군/인조 대에 활발히 이루어진 사찰 중건 과정에서 재건되었습니다. 대웅전 내에는 흙으로 빚어 만든 삼세불상(소조석가여래삼존불좌상)이 모셔져 있습니다.'),
('joseon', '전주', '전주 경기전(사적)에 봉안되어 있는 조선의 국왕 어진(초상화)은 누구의 어진인가요?', array['태종 이방원', '태조 이성계', '세종 이도', '정조 이산'], 1, '경기전은 조선을 건국한 태조 이성계의 영정(초상화인 어진, 국보)을 봉안하기 위해 태종 10년(1410년)에 창건되었습니다.'),
('joseon', '전주', '오목대는 태조 이성계가 고려 우왕 시절 어느 전투에서 왜구를 크게 무찌르고 개경으로 돌아가던 길에 종친들과 잔치를 베푼 곳인가요?', array['홍산대첩', '진포대첩', '황산대첩', '관음포대첩'], 2, '이성계는 1380년 삼남 지방을 약탈하던 왜구를 황산(현재 전북 남원)에서 크게 격퇴한 ''황산대첩''을 거두고 개경으로 귀환하던 도중, 전주 오목대에서 친지들과 잔치를 벌이며 왕조 창업의 야망을 한시로 읊었습니다.'),
('joseon', '전주', '조선시대 전라감영의 소재지였던 전주를 둘러싸고 있던 전주부성의 남문이자, 성문 중 유일하게 남아있는 보물은 무엇인가요?', array['풍남문', '동고문', '서평문', '패엽문'], 0, '풍남문은 전주부성의 남문으로 임진왜란 때 파괴되었다가 영조 때 재건되었습니다. 전주부성의 4대문 중 유일하게 현존하는 유적이며 보물로 지정되어 있습니다.'),
('joseon', '남원', '남원의 광한루원에 대한 설명으로 가장 알맞은 것은 무엇인가요?', array['견훤이 고려에 대항하여 축성한 산성 정원이다.', '백제 무왕이 궁궐 연못으로 조성한 정원이다.', '조선의 명승이자 소설 ''춘향전''의 배경으로 신선사상과 전통 정원 양식이 조화를 이룬 곳이다.', '구한말 의병들이 연합 전선을 펼쳤던 역사적 격전지이다.'], 2, '광한루원은 조선 시대의 대표적인 정원으로, 신선들이 산다는 전설 속 삼신산을 연못 위에 구현한 전통 조경 양식을 보여줍니다. 고대 소설 ''춘향전''에서 이몽룡과 성춘향이 처음 만난 장소로 유명합니다.'),
('baekje', '익산', '백제 무왕 때 건립된 동양 최대의 사찰 터인 익산 미륵사지에서 발견된 국보 제11호 미륵사지 석탑과 관련된 설명으로 옳은 것은?', array['목탑의 양식을 석재로 구현한 과도기적 석탑이자 한국 석탑의 시원(시작)으로 평가된다.', '고구려의 양식을 완벽히 이어받은 육각형 탑이다.', '1990년대에 한반도 최초로 발굴된 유리 탑이다.', '돌이 아닌 붉은 벽돌만을 쌓아서 만든 전탑이다.'], 0, '익산 미륵사지 석탑(국보)은 목조건축의 기법을 석재로 충실히 구현한 독특한 과도기 양식을 띠고 있어, 한국 석탑의 출발점으로 역사적 가치가 큽니다.'),
('baekje', '익산', '백제 무왕 시기 왕궁으로 조성된 익산 왕궁리 유적에서 확인된 독특하고 선진적인 고대 생활사 유적은 무엇인가요?', array['온수 순환 방식의 구들장(보일러)', '대형 화장실 유적과 똥분석을 통한 기생충 흔적', '지하식 천문대(혼천의)', '천연 탄산수 온천탕 복합시설'], 1, '익산 왕궁리 유적에서는 한국 고대 유적 최초로 대형 공동화장실 터와 나무 주걱(뒤처리용), 그리고 화장실 흙 분석을 통한 회충 등 기생충 알이 검출되어 고대인들의 청결/위생 생활상을 직접 증명해 주었습니다.'),
('later_baekje', '전주', '전주 동고산성은 삼국사기에 기록된 어느 나라의 궁성(도성) 터로 비정되고 있나요?', array['백제', '후고구려', '가야', '후백제'], 3, '전주 동고산성은 900년 견훤이 완산주(현재의 전주)에 도읍을 정하고 세운 후백제의 궁성(도성) 터로 유력하게 추정되며, 대형 건물지 유적이 발굴되었습니다.'),
('later_baekje', '전주', '전주 승암산성(치명자산성)의 주된 역사적 역할은 무엇이었나요?', array['가야의 대일본 해상 무역 전초 기지', '후백제의 도성(완산주) 방어를 위한 동방 외곽 방어 요새', '임진왜란 당시 전주사고의 실록을 보관한 장소', '일제강점기 쌀 수탈을 감시하던 감시탑'], 1, '승암산성은 완산주(전주)의 동쪽을 병풍처럼 둘러싸고 있는 승암산 일대에 축성되어 후백제 도성의 동쪽 방어를 담당했던 핵심 보루이자 전략 요새였습니다.'),
('later_baekje', '김제', '후백제의 시조 견훤이 넷째 아들 금강에게 왕위를 물려주려 하자, 이에 분노한 큰아들 신검 등에 의해 유배당했던 비극적인 역사의 현장은 어디인가요?', array['김제 금산사', '익산 미륵사', '완주 송광사', '남원 만복사'], 0, '견훤은 왕위 계승 분쟁 과정에서 큰아들 신검과 그 무리에 의해 김제 금산사에 3개월 동안 유금(유배)당했다가 탈출하여 고려 태조 왕건에게 투항하였습니다.'),
('goryeo', '익산', '보물로 지정된 익산 고도리 석조여래입상은 약 200m 거리를 두고 두 석상이 마주 보고 서 있습니다. 이 둘의 흥미로운 전설은 무엇인가요?', array['해마다 단오 날이 되면 동서로 마주보고 춤을 춘다.', '평소에는 떨어져 있다가, 섣달그믐날 밤 음력 12월 말에 냇물이 얼면 만나 포옹을 나눈다.', '왕궁리 5층석탑을 함께 옮겼다는 전설이 있다.', '나라에 큰 난리가 나기 전에 석상에서 눈물이 흘러내린다.'], 1, '고도리 석조여래입상은 동서로 약 200미터 떨어져 냇물을 사이에 두고 서 있습니다. 전설에 따르면 평소에는 서로 만나지 못하다가, 일 년 중 마지막 날 밤(섣달그믐날)에 냇물이 얼어붙으면 두 불상이 건너와서 만났다가 새벽 닭이 울면 다시 제자리로 돌아간다고 전해집니다.'),
('goryeo', '남원', '남원 만복사지는 고려 시대에 세워져 김시습의 한문 소설의 배경이 된 절터입니다. 이 소설의 이름은 무엇인가요?', array['구운몽', '홍길동전', '만복사저포기', '춘향전'], 2, '만복사지는 매월당 김시습이 지은 한국 최초의 한문 소설집 ''금오신화''에 수록된 ''만복사저포기(萬福寺樗蒲記)''의 배경입니다. 주인공 양생이 만복사 불당에서 부처님과 저포(주사위 놀이)를 해 이겨 아름다운 여인의 영혼과 애틋한 사랑을 나누는 이야기입니다.'),
('modern', '군산', '군산 근대역사박물관이 위치한 군산항은 일제강점기 당시 어떤 역사적 수탈과 연관이 깊은 곳인가요?', array['평양 대동강 유역의 철광석 수탈', '호남 평야 일대의 쌀 수탈과 일본 반출', '한라산의 울창한 목재 수탈', '태백산맥의 석탄 자원 수탈'], 1, '군산은 일제강점기 호남평야에서 생산된 쌀을 일본으로 수탈해 가던 핵심 항구 도시였습니다. 박물관은 이 같은 아픈 역사와 일제에 저항한 군산 시민들의 항일 운동을 상세히 다루고 있습니다.'),
('modern', '군산', '군산 신흥동 일본식 가옥은 일제강점기 군산에서 대규모 포목상과 농장을 운영했던 일본인이 지은 주택입니다. 이 가옥의 건축사적 가치는 무엇인가요?', array['전형적인 조선 후기 사대부 가옥의 양식을 보여준다.', '한옥과 양식 건축이 결합한 절충형 기독교 예배당이다.', '일제강점기 일본인 지주나 부유층의 전형적인 일본식 주택 및 정원의 모습을 고스란히 간직하고 있다.', '백제 전통 점토 가마터의 구조를 따르고 있다.'], 2, '신흥동 일본식 가옥(구 히로쓰 가옥)은 목조 2층 주택으로, 일제강점기 당시 부유한 일본인 지주의 전형적인 주택 양식과 일본식 정원 배치를 온전히 유지하고 있어 근대 주거 생활사를 연구하는 데 중요한 사료가 됩니다.'),
('prehistoric', '고창', '고창 고인돌 유적은 유네스코 세계문화유산으로 지정된 대표적인 선사시대 유적입니다. 이곳에 조밀하게 분포한 고인돌은 청동기 시대의 어떤 성격을 보여주는 무덤인가요?', array['지배계급의 무덤이자 거석문화의 상징', '불교 식장 제례를 위한 탑', '기우제를 지내던 제단', '사료를 저장하던 창고'], 0, '고창 고인돌 유적은 청동기 시대의 대표적인 무덤 형식인 고인돌이 단일 구역 내에 세계에서 가장 조밀하게 분포한 곳입니다. 이는 당시 지배 계급의 발생과 거석문화의 발전 양상을 잘 보여줍니다.'),
('joseon', '고창', '고창읍성(모양성)에서 전해지는 전통 풍습으로, 돌을 머리에 이고 성곽을 돌며 무병장수와 사후 극락행을 기원하는 민속 행사는 무엇인가요?', array['답성놀이 (성밟기)', '차전놀이', '놋다리밟기', '고싸움놀이'], 0, '고창읍성에서는 머리에 돌을 이고 성곽을 도는 ''답성놀이(성밟기)'' 풍습이 유명합니다. 한 바퀴 돌면 다리병이 낫고, 두 바퀴 돌면 무병장수하며, 세 바퀴 돌면 극락에 간다는 설화가 전해집니다.'),
('joseon', '정읍', '정읍 무성서원은 최치원 선생을 모시기 위해 세워진 조선시대의 사원입니다. 이곳이 다른 서원들과 비교해 가지는 특별한 역사적 가치는 무엇인가요?', array['을사늑약 체결 당시 호남 지역 최초로 의병을 일으킨 역사적 항일 발상지이다.', '조선 왕조의 불교 억압 정책에 맞서 일어난 절터이다.', '동학 농민 운동의 마지막 전투가 열렸던 지휘소였다.', '우리나라 최초의 여성 유학자를 배출한 서원이다.'], 0, '정읍 무성서원은 1906년 면암 최익현 선생이 을사늑약에 항거하여 호남 최초의 의병을 일으켰던 항일 독립운동의 유서 깊은 발상지이기도 합니다.'),
('joseon', '부안', '부안 내소사의 대웅보전(보물) 꽃살문 조각에 대한 설명으로 가장 어울리는 것은 무엇인가요?', array['정교한 불교 조각 예술의 정수로, 나뭇결 그대로 연꽃과 국화 무늬를 세련되게 조각했다.', '삼국시대 백제 양식의 화려한 청동 꽃 장식을 박아 넣었다.', '중국 당나라 수입 목재를 사용해 웅장한 용 무늬를 조각했다.', '서양 기하학 무늬를 적용한 현대적인 디자인이다.'], 0, '내소사 대웅보전의 문살은 연꽃과 국화꽃 등을 쇠못을 쓰지 않고 나무로만 정교하게 맞추어 조각한 조선 중기 전통 목조건축 미술의 극치로 꼽힙니다.'),
('baekje', '김제', '김제 벽골제는 백제 비류왕 때 축조된 우리나라 역사상 가장 오래된 대표적인 수리시설입니다. 벽골제가 축조된 주목적은 무엇인가요?', array['농업 생산력을 높이기 위해 드넓은 김제 평야에 물을 대는 저수지 둑이었다.', '적들의 침입에 대비해 도성을 방어하는 거대한 해자였다.', '조선 건국을 기념하기 위해 조성한 왕실 인공 연못이었다.', '근대 해상 물류의 중심지로 기능한 인공 운하였다.'], 0, '김제 벽골제는 삼국시대 당시 벼농사 중심의 농업 생산력을 획기적으로 증대시키기 위해 건설된 거대 인공 방조제이자 우리나라 최초의 고대 저수지 둑입니다.'),
('joseon', '무주', '무주 적상산성(사적) 내에 건립되어 조선왕조실록과 왕실 족보 등을 임진왜란 이후 안전하게 보관했던 역사의 보고는 무엇인가요?', array['적상산 사고 (Sagobang)', '적상사 미륵전', '태조 영당', '적상 해인사'], 0, '적상산성은 사방이 깎아지른 절벽으로 둘러싸인 천혜의 요새로, 임진왜란 이후 조선 왕조의 핵심 역사 기록물인 ''조선왕조실록''을 안전하게 영구 보존하기 위해 적상산 사고가 건립되었습니다.'),
('joseon', '정읍', '호남 제일의 누각이라 불리는 정읍 피향정은 여름에 연못 위에 펼쳐지는 어떤 식물의 아름다운 풍경과 향기로 유명한가요?', array['연꽃', '매화', '벚꽃', '대나무'], 0, '피향정(보물)은 연못에 가득 핀 연꽃의 향기가 사방에 그윽하게 번진다는 뜻에서 붙여진 이름으로, 신라의 최치원 선생이 연못가를 거닐며 풍류를 즐겼다는 설화가 전해집니다.'),
('goryeo', '남원', '지리산 자락에 위치한 남원 실상사는 구산선문 중 최초로 문을 연 유서 깊은 사찰입니다. 실상사가 가진 독특한 풍수지리적 설립 배경은 무엇인가요?', array['일본이나 외부의 나쁜 기운이 한반도로 들어오는 것을 지리산에서 누르기 위해 세워졌다.', '백제 왕실의 무덤 자리를 수호하기 위해 세워졌다.', '근대 항일 운동의 비밀 화약고를 숨기기 위해 세워졌다.', '가장 비옥한 영토의 풍요를 기원하는 신전이었다.'], 0, '실상사는 신라 선종의 발상지로, 풍수지리적으로 한반도의 기운이 일본으로 빠져나가는 것을 막고 왜의 나쁜 기운을 지리산 자락에서 제압하려는 호국 사상의 배경을 품고 있습니다.'),
('baekje', '익산', '익산 쌍릉은 대왕묘와 소왕묘로 구성된 백제 시대의 고분입니다. 이 무덤들의 역사적 주인공으로 가장 높게 비정되는 인물은 누구인가요?', array['백제 무왕 (King Mu)', '백제 근초고왕', '백제 의자왕', '백제 온조왕'], 0, '익산 쌍릉(사적)은 백제 말기 무왕(대왕묘)과 그의 왕비 선화공주(소왕묘)의 능으로 추정되며, 백제의 익산 천도 혹은 복도(수도를 두 군데 둠) 설을 증명하는 고대 고분 유적입니다.'),
('goryeo', '임실', '임실 성수산에 위치한 상이암은 두 태조와 인연이 깊습니다. 상이암에서 기도를 드려 건국을 이루었다고 전해지는 두 인물은 누구인가요?', array['고려 태조 왕건과 조선 태조 이성계', '백제 온조왕과 고려 태조 왕건', '신라 경순왕과 조선 태조 이성계', '고려 태조 왕건과 조선 태종 방원'], 0, '임실 상이암은 고려를 건국한 왕건과 조선을 건국한 이성계가 하늘의 계시(삼청동 성수산의 맑은 기운)를 받고 건국 대업을 이루었다는 창업 설화가 함께 전해지는 유서 깊은 암자입니다.'),
('joseon', '진안', '진안 마이산 탑사에 약 80여 개의 돌탑을 쌓아 올렸으며, 비바람에도 무너지지 않는 신비한 탑사 풍경을 일군 조선 후기 처사는 누구인가요?', array['이갑용 처사', '임경업 장군', '서산대사', '원효대사'], 0, '진안 마이산 탑사는 이갑용 처사가 1800년대 후반부터 평생 동안 접착제나 시멘트 없이 자연석만으로 80여 개의 돌탑을 쌓아 올린 신비로운 역사 유적입니다.'),
('joseon', '전주', '조선시대 전라도의 대표적인 교육기관이었던 전주향교에는 공자를 비롯한 성현들의 위패를 모신 전각이 있습니다. 이 전각의 이름은 무엇인가요?', array['대성전', '명륜당', '동무', '서무'], 0, '전주향교 대성전(보물)은 공자를 비롯한 유교 성현들의 위패를 모시고 제사를 지내는 전주향교의 핵심 전각입니다.'),
('joseon', '정읍', '1894년 전봉준이 이끄는 동학농민군이 전라감영의 관군을 상대로 첫 대승을 거두었던 전투의 장소이자, 현재 사적으로 지정된 이곳은 어디일까요?', array['황토현 전적지', '우금치 전적지', '황룡촌 전적지', '백산 전적지'], 0, '정읍 황토현 전적(사적)은 1894년 동학농민군이 관군과의 첫 전면전에서 대승을 거둠으로써 동학농민혁명이 전국적으로 확산되는 결정적 계기가 된 격전지입니다.'),
('goryeo', '고창', '고창 선운사는 천연기념물로 지정된 동백나무 숲으로도 유명합니다. 대웅보전(보물) 뒤편에 위치한 이 동백나무 숲은 주로 어떤 실용적 목적으로 조성되었다고 전해지나요?', array['사찰에 화재가 발생했을 때 불길을 막는 방화림 역할', '동백기름을 만들어 왕실에 상공하기 위한 용도', '왜구의 침입을 감시하기 위한 은폐막', '차나무 그늘을 만들기 위한 용도'], 0, '선운사 대웅전 뒤편 산기슭에는 약 3천여 그루 of 동백나무가 숲을 이루고 있습니다. 동백나무의 두껍고 수분이 많은 잎은 산불이나 화재 시 불길이 전각으로 번지는 것을 막아주는 천연 방화림 역할을 했습니다.'),
('joseon', '남원', '조선 선조 때 정유재란 당시, 남원성 전투에서 침략한 왜군에 맞서 싸우다 순국한 민·관·군 의사들의 유해를 함께 모신 호국 무덤의 이름은 무엇인가요?', array['만인의총', '칠백의총', '칠천량묘', '삼백의총'], 0, '남원 만인의총(사적)은 1597년 정유재란 당시 왜군에 맞서 최후까지 남원성을 지키다 순절한 피난민, 관군, 의병 등 약 1만여 명의 호국영령들을 한곳에 합장하여 모신 무덤입니다.'),
('goryeo', '완주', '완주 화암사 극락전은 국보로 지정되어 있습니다. 이 건물은 한국 건축 문화재 중 유일하게 지붕 처마의 무게를 분산시키는 어떤 특별한 건축 공법을 사용했나요?', array['하앙(하앙) 구조', '다포(多包) 구조', '주심포(柱心包) 구조', '민도리 구조'], 0, '완주 화암사 극락전(국보)은 중국이나 일본에는 흔하지만 한국 목조건축 중에서는 유일하게 보존되어 있는 ''하앙(下昂) 구조''를 채택한 건물입니다. 하앙은 기둥 위에서 처마를 길게 내밀 수 있도록 지탱해 주는 목재 부재입니다.');